import{_ as a,o as e,c as p,j as r,a as t,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const T=JSON.parse('{"title":"4.合体技","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/4.合体技.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/4.合体技.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/Try another story/4.合体技.md"};function n(d,b,i,_,l,c){return e(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"_4-合体技",tabindex:"-1"},[t("4.合体技 "),r("a",{class:"header-anchor",href:"#_4-合体技","aria-label":'Permalink to "4.合体技"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="合体技" tabindex="-1">合体技 <a class="header-anchor" href="#合体技" aria-label="Permalink to &quot;合体技&quot;">​</a></h1><p>合体技<br> 合体技的发动需要你在自己的回合进行准备，满足特殊条件的队友同样选择合体技才能发动。<br> 这需要你们两者同时购买了同一个技能，并依次在自己的回合内消费动作执行对应的行动。<br> 使用合体技时，你必须将自身的先攻延迟到对应习得合体技队友之前或之后（或者对方延迟到你的前或后），再执行对应的行动，这会被称为【前置】与【后置】，产生不同的效果（依旧需要满足对应的攻击检定模式）。<br> 无论前置还是后置，你和那个队友视为在同一回合内发动了合体技攻击。</p><p>限制：合体技的前置要求需要不同的轮回者分别购买了不同前置的概念武装，进行组合搭配才能使用。</p><p>TiroSperdere准备<br> 限制：概念武装-Moschetto<br> 或概念武装-火器类等<br> 价格：C+1500<br> 动作：标准动作<br> 类型：攻击技<br> 消耗：6点SG<br> 范围：半径15+传奇智力*5米<br> 目标：射程内任意一个目标<br> 描述：黑色与黄色魔法少女的合体技，由一者打出攻击，随后另一者追加攻击使子弹扩散，来给予全体敌人伤害，也被称为“扩散攻击”。<br> 效果：<br> 【前置】进行一次普通枪械攻击，这次枪械攻击是范围攻击，以命中单位为中心造成范围伤害，同时攻击范围内的所有敌对目标，目标使用反射豁免。<br> 本次攻击将获得自身射击技能附加*5点高速，因此获得的高速上限为12点。</p><p>【后置】进行一次普通枪械攻击，这次枪械攻击是范围攻击，以命中单位为中心造成范围伤害，同时攻击范围内的所有敌对目标，目标使用反射豁免。<br> 本次攻击将获得自身射击技能附加*1点附加与攻击速度加值。</p><p>多重Arme Presa准备<br> 限制：概念武装-佩剑&amp;鞘<br> 或概念武装-火器类等<br> 价格：C+1250<br> 动作：标准动作<br> 类型：攻击技<br> 消耗：6点SG<br> 范围：见下<br> 目标：触及/射程范围内任意一个目标<br> 描述：黑色与蓝色魔法少女的合体技，攻击后不知为何的给予自身速度上的提升，是手牵手在停止时间里放出Arme Presa的能力。<br> 效果：<br> 【前置】进行一次普通近战攻击检定，由于时间的停止，攻击动作对于敌人而言是瞬间的速度，因此本次攻击获得B级措手不及的效果，在攻击后使自身传奇敏捷*10米的移动速度提升。<br> 移动速度提升的效果持续一场景，多次发动不叠加。</p><p>【后置】进行一次普通枪械攻击检定，由于时间的停止，攻击动作对于敌人而言是瞬间的速度，因此本次攻击获得B级措手不及的效果，在攻击后使自身在攻击检定上获得传奇敏捷*2DP的速度加值，以及移动速度提升传奇敏捷*5米。<br> 攻击加值与提升的速度会持续一场景，多次发动不叠加。</p><p>光之矢准备<br> 限制：概念武装-魔法之弓<br> 或概念武装-火器类<br> 价格：C+1500<br> 动作：标准动作<br> 类型：攻击技<br> 消耗：6点SG<br> 范围：见下<br> 目标：射程范围内任意一个目标<br> 描述：黑色与粉色魔法少女的合体技，握住她的手，放出注入两人魔力的箭。<br> 效果：<br> 【前置】进行一次普通弓箭攻击检定，本次攻击附带【能量武器】特性，以及【湮灭】效果。<br> 此外，在本次攻击中你获得自身传奇决心*1点增强加值，伤害类型转变为光能。</p><p>【后置】进行一次普通枪械射击检定，本次攻击附带【能量武器】特性，以及【湮灭】效果。<br> 此外，在本次攻击中你获得自身传奇决心*1点附加成功，伤害类型转变为光能。</p><p>圣枪朗基努斯准备<br> 限制：概念武装-多节枪<br> 或概念武装-火器类<br> 价格：C+1250<br> 动作：标准动作<br> 类型：攻击技<br> 消耗：6点SG<br> 范围：见下<br> 目标：触及/射程范围内任意一个目标<br> 描述：黑色与红色魔法少女的合体技，向缚锁结界多次射击，最后连结界也贯穿，粗暴地进行强力无比的一击。<br> 效果：<br> 【前置】进行一次普通近战攻击检定，本次攻击将附带等同伤害出目的纠缠不良点数，同时在攻击检定中获得自身传奇操纵*1点增强加值。</p><p>【后者】进行一次普通枪械攻击检定，本次攻击附带【接触攻击】特性，攻击检定中获得传奇智力*1点的增强加值，以及等同于自身敏捷/3点附加成功。</p><p>TiroBaldo准备<br> 限制：概念武装-Moschetto<br> 或概念武装-佩剑&amp;鞘<br> 价格：C+1000<br> 动作：标准动作<br> 类型：攻击技<br> 消耗：6点SG<br> 范围：见下<br> 目标：触及/射程范围内任意一个目标<br> 描述：黄色与蓝色魔法少女的合体技，用剑刃在目标身上刻下五芒星，随着信号一同解放魔力产生攻击。<br> 效果：<br> 【前置】进行一次普通近战攻击检定，本次攻击在命中后，额外造成自身传奇敏捷*1点韧性伤害。<br> 此时计算造成的额外韧性伤害，每具有1点，则使被命中的目标在受到TiroBaldo准备的后置攻击时，若没能完全豁免，就高在豁免结果减少等同你的传奇敏捷*1+1点成功数。</p><p>【后置】进行一次普通枪械攻击检定，本次攻击附带【幻灭】特性，命中后使目标以强韧检定进行豁免，而不是正常防御。</p><p>TiroLancia准备<br> 限制：概念武装-Moschetto<br> 或概念武装-多节枪<br> 价格：C+1000<br> 动作：标准动作<br> 类型：攻击技<br> 消耗：6点SG<br> 范围：见下<br> 目标：触及/射程范围内任意一个目标<br> 描述：黄色与红色魔法少女的合体技，两人产生的最大火力融合，产生强力的破坏威力。<br> 【前置】进行一次普通近战攻击检定，本次攻击附带【崩击】特性。</p><p>【后置】进行一次普通枪械攻击检定，本次攻击附带【崩击】特性，以及额外在这次攻击检定上获得等同自身传奇力量*1点的增强加值。</p><p>【崩击】当你使用本武器进行攻击时，若你成功造成伤害，如同对对方造成了一次击退，受害者正常检定对抗这次攻击成功数。如果失败，则会往后移动失败差额米，同时陷入伏地状态。<br> 如果中途撞到障碍物，则会附加等同于伤害出目的晕眩不良点数，正常豁免，可叠加，造成的点数上限为造成击退距离米数。</p><p>交错突刺准备<br> 限制：概念武装-佩剑&amp;鞘<br> 或概念武装-多节枪<br> 价格：C+1000<br> 动作：标准动作<br> 类型：攻击技<br> 消耗：6点SG<br> 范围：见下<br> 目标：触及范围内任意一个目标<br> 描述：蓝色与红色魔法少女放出的合体技，两人产生的最大火力融合，产生强力的破坏威力。<br> 效果：<br> 【前置】进行一次普通近战攻击检定，本次攻击附带【超级贯穿】特性。同时使武器在这次攻击中获得等同于你的力量*1点破甲效果</p><p>【后置】进行一次普通近战攻击检定，本次攻击附带【超级贯穿】特性。同时使武器在这次攻击中获得等同于你的力量*1点破甲效果。<br> 若攻击结算后仍有剩余的破甲，则你可以将这个效果提供的破甲转化为等量的攻击增强加值。</p><p>共鸣治愈准备<br> 限制：无<br> 价格：C+1000<br> 动作：标准动作<br> 类型：特殊<br> 范围：15+传奇决心*5米<br> 目标：见下<br> 消耗：3点SG<br> 持续：立刻<br> 描述：治愈魔法产生共鸣，为一定范围内的友方恢复生命值，也能略微减少异常状态的效果的合体技。<br> 效果：这是一个特殊的合体技，并不要求有着对应颜色或者武器，只要是购买了Try another story主干部分就能进行购买，其他部分如同正常合体技一样处理。</p><p>【前置】以自身为中心，范围内的所有友方单位获得6点快速医疗效果，共用医疗池72点。<br> 若你只为了满足后置异常点医疗效果的而发动前置效果，只要范围内的单位生命值处于完好状态，你就可以不消耗能量只使用动作维持。<br> 你也可以在购买时选择将快速医疗效果降低1点，共用医疗池上限降低12点，使这一合体技在进行再生肢体时，可以无需消耗能量，只需要动作维持。</p><p>【后置】以自身为中心，范围内的所有友方单位获得3点异常点数医疗效果，共用医疗池72点，与前置的医疗池分别独立。<br> 你在使用后置效果时，无需支付能量，只需要支付动作就可以正常维持使异常点数医疗的效果生效。</p><p>特殊的是，购买共鸣治愈准备不会获得自由属性。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',24)])])}const m=a(s,[["render",n]]);export{T as __pageData,m as default};
